import React, { useState, useContext } from 'react';
import { View, TextInput, Button, Text, StyleSheet } from 'react-native';
import { AppContext } from '../context/AppContext';

export default function JoinGroupScreen({ navigation }) {
  const [groupId, setGroupId] = useState('');
  const [message, setMessage] = useState('');
  const { joinGroupById } = useContext(AppContext);

  const handleJoin = () => {
    const res = joinGroupById(groupId.trim());
    if (res.success) {
      navigation.replace('Chat', { groupId: groupId.trim() });
    } else {
      setMessage(res.message || 'ไม่สามารถเข้าร่วมได้');
    }
  };

  return (
    <View style={styles.container}>
      <TextInput placeholder="กรอก Group ID (ตัวอย่าง: g-123)" value={groupId} onChangeText={setGroupId} style={styles.input} />
      <Button title="เข้าร่วมกลุ่ม" onPress={handleJoin} />
      {message ? <Text style={{ color: 'red', marginTop: 8 }}>{message}</Text> : null}
    </View>
  );
}

const styles = StyleSheet.create({ container: { flex: 1, padding: 16 }, input: { borderWidth: 1, borderColor: '#ccc', padding: 10, borderRadius: 6, marginBottom: 12 } });
